#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-07-23

# Guards the coverage contract of tests/security/test-npm-audit.sh.
#
# Why this exists: the audit gate spent its whole life auditing 2 of the 4 trees
# it claimed to cover — a missing node_modules returned 0 (pass), and CI installed
# only root + src/hooks, so docs/site and src/mcp-server were silently skipped and
# 5 high advisories were never reported (#3088). #3090 fixed it by auditing
# --package-lock-only (reads the lockfile, needs no install) and making a missing
# lockfile a hard failure. That fix has no test of its own; this is it.
#
# Structural on purpose: it inspects the gate rather than running it, so it stays
# deterministic and network-free (npm audit hits registry.npmjs.org). It locks in
# exactly the three properties whose regression reintroduces #3088.

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="$(cd "$SCRIPT_DIR/../.." && pwd)"
GATE="${AUDIT_GATE:-$PROJECT_ROOT/tests/security/test-npm-audit.sh}"

RED=$'\033[0;31m'
GREEN=$'\033[0;32m'
NC=$'\033[0m'
PASS=0
FAIL=0
pass() { echo "  ${GREEN}✓${NC} $1"; PASS=$((PASS + 1)); }
fail() { echo "  ${RED}✗${NC} $1"; FAIL=$((FAIL + 1)); }

if [[ ! -f "$GATE" ]]; then
  echo "  ${RED}✗${NC} audit gate not found at $GATE"
  exit 1
fi

# 1. Every tree with a package.json is audited. A tree silently dropped from the
#    loop is the #3088 regression.
mapfile -t TREES < <(cd "$PROJECT_ROOT" && \
  for d in . docs/site src/hooks src/mcp-server; do
    [[ -f "$d/package.json" ]] && echo "$d"
  done)
for tree in "${TREES[@]}"; do
  label="$tree"; [[ "$tree" == "." ]] && label="root"
  if grep -qE "^audit_project +\"${label}\"" "$GATE"; then
    pass "audits ${label}"
  else
    fail "tree '${label}' has a package.json but the gate does not audit it"
  fi
done

# The count must match, so a NEW tree can't be added without wiring the gate.
invocations=$(grep -cE '^audit_project +"' "$GATE")
if [[ "$invocations" -eq "${#TREES[@]}" ]]; then
  pass "audit_project invocation count (${invocations}) matches package.json trees (${#TREES[@]})"
else
  fail "gate audits ${invocations} trees but ${#TREES[@]} have package.json"
fi

# 2. The audit reads the LOCKFILE, not node_modules. Dropping --package-lock-only
#    reintroduces the install dependency that caused the silent skip.
if grep -qE 'npm audit .*--package-lock-only' "$GATE"; then
  pass "audits --package-lock-only (no node_modules dependency)"
else
  fail "npm audit invocation lost --package-lock-only — reverts to node_modules coverage"
fi

# 3. A missing lockfile must FAIL, never pass. The original bug was a skip that
#    returned 0.
if grep -qE 'package-lock\.json' "$GATE" \
   && grep -A4 'if \[\[ ! -f "\$dir/package-lock.json" \]\]' "$GATE" | grep -q 'return 1' \
   && ! grep -A4 'if \[\[ ! -f "\$dir/package-lock.json" \]\]' "$GATE" | grep -q 'return 0'; then
  pass "a missing lockfile hard-fails (no skip-equals-pass)"
else
  fail "the missing-lockfile branch does not hard-fail — a tree could pass by not running"
fi

echo
echo "  ${GREEN}${PASS} passed${NC}, ${RED}${FAIL} failed${NC}"
[ "$FAIL" -eq 0 ]
